class TTLCache:
    def __init__(self, now):
        self._now = now
        self._items = {}

    def put(self, key, value, ttl):
        self._items[key] = (value, self._now(), ttl)

    def get(self, key):
        item = self._items.get(key)
        if item is None:
            return None
        value, created, ttl = item
        if self._now() - created <= ttl:
            return value
        return None

