import threading, time, pytest
from src.memo import memoize

def test_same_key_computed_once_concurrently():
    calls=[]
    def compute(key): calls.append(key); time.sleep(0.05); return key*2
    fn=memoize(compute); results=[]
    threads=[threading.Thread(target=lambda:results.append(fn(3))) for _ in range(4)]
    [t.start() for t in threads]; [t.join() for t in threads]
    assert results==[6,6,6,6] and calls==[3]

def test_different_keys_are_not_blocked_by_slow_owner():
    started=threading.Event(); release=threading.Event(); second_done=threading.Event()
    def compute(key):
        if key == 'slow':
            started.set(); release.wait(timeout=1)
        return key
    fn=memoize(compute)
    first=threading.Thread(target=lambda:fn('slow')); first.start(); assert started.wait(timeout=1)
    second=threading.Thread(target=lambda:(fn('fast'), second_done.set())); second.start()
    assert second_done.wait(timeout=0.2)
    release.set(); first.join(timeout=1); second.join(timeout=1)

def test_exception_is_not_cached():
    calls=[]
    def compute(key):
        calls.append(key)
        if len(calls)==1: raise RuntimeError('first')
        return 9
    fn=memoize(compute)
    with pytest.raises(RuntimeError): fn('x')
    assert fn('x')==9 and calls==['x','x']

